// Detect whether payload is from Meta Lead Form or Google Lead Form
const input = $input.first().json;
const body = input.body || input;

let source = 'unknown';
let rawLead = body;

// Meta / Facebook Lead Form indicators
if (body.lead_id || body.leadgen_id || body.form_id || body.page_id ||
    (body.entry && Array.isArray(body.entry))) {
  source = 'facebook_lead_form';
  if (body.entry && body.entry[0]?.changes) {
    const change = body.entry[0].changes[0]?.value || {};
    rawLead = {
      lead_id: change.leadgen_id || change.lead_id,
      form_id: change.form_id,
      page_id: change.page_id,
      ad_id: change.ad_id,
      created_time: change.created_time,
      field_data: change.field_data || body.field_data || []
    };
  }
}
else if (body.gcl_id || body.google_key || body.campaign_id ||
         body.user_column_data || body.gclid ||
         (body.form_data && (body.campaign_name || body.campaign_id))) {
  source = 'google_lead_form';
  rawLead = body;
}
else if (body.platform === 'facebook' || body.platform === 'meta') {
  source = 'facebook_lead_form';
} else if (body.platform === 'google' || body.platform === 'google_ads') {
  source = 'google_lead_form';
}

return [{ json: { source, rawLead, _receivedAt: new Date().toISOString() } }];

const input = $input.first().json;
const { source, rawLead, _receivedAt } = input;

function getMetaField(fieldData, ...names) {
  if (!Array.isArray(fieldData)) return null;
  for (const name of names) {
    const field = fieldData.find(f =>
      (f.name || '').toLowerCase() === name.toLowerCase() ||
      (f.label || '').toLowerCase().includes(name.toLowerCase())
    );
    if (field) return (field.values && field.values[0]) || field.value || null;
  }
  return null;
}

let normalized = {
  firstName: null, lastName: null, email: null, phone: null,
  source: source, campaign: null, adName: null, formId: null,
  vehicleInterest: null,
  consent: 'implied',
  consentNote: 'Form submission constitutes implied consent under CASL - 6-month window from submission date',
  consentDate: _receivedAt,
  consentExpiry: new Date(Date.now() + 6 * 30 * 24 * 60 * 60 * 1000).toISOString(),
  timestamp: _receivedAt, rawLeadId: null, _raw: rawLead
};

if (source === 'facebook_lead_form') {
  const fd = rawLead.field_data || [];
  normalized.firstName = getMetaField(fd, 'first_name', 'firstname', 'prenom') || rawLead.first_name || null;
  normalized.lastName = getMetaField(fd, 'last_name', 'lastname', 'nom') || rawLead.last_name || null;
  normalized.email = getMetaField(fd, 'email', 'courriel', 'email_address') || rawLead.email || null;
  normalized.phone = getMetaField(fd, 'phone_number', 'phone', 'telephone', 'tel') || rawLead.phone || null;
  normalized.campaign = rawLead.campaign_name || rawLead.campaign || null;
  normalized.adName = rawLead.ad_name || rawLead.ad_id || null;
  normalized.formId = rawLead.form_id || null;
  normalized.rawLeadId = rawLead.lead_id || rawLead.leadgen_id || null;
  normalized.vehicleInterest = getMetaField(fd, 'vehicle', 'vehicle_interest', 'vehicule', 'make_model', 'which_vehicle', 'quel_vehicule') || null;
  if (!normalized.vehicleInterest) {
    const make = getMetaField(fd, 'make', 'marque');
    const model = getMetaField(fd, 'model', 'modele');
    if (make || model) normalized.vehicleInterest = [make, model].filter(Boolean).join(' ');
  }
  if (!normalized.firstName) {
    const fullName = getMetaField(fd, 'full_name', 'name', 'nom_complet') || rawLead.full_name;
    if (fullName) {
      const parts = fullName.trim().split(/\s+/);
      normalized.firstName = parts[0] || null;
      normalized.lastName = parts.slice(1).join(' ') || normalized.lastName;
    }
  }
} else if (source === 'google_lead_form') {
  const ucd = rawLead.user_column_data || [];
  function getGoogleField(...names) {
    for (const name of names) {
      const field = ucd.find(f =>
        (f.column_id || '').toLowerCase().includes(name.toLowerCase()) ||
        (f.column_name || '').toLowerCase().includes(name.toLowerCase())
      );
      if (field) return field.string_value || field.value || null;
    }
    return null;
  }
  normalized.firstName = getGoogleField('first_name', 'given_name') || rawLead.first_name || null;
  normalized.lastName = getGoogleField('last_name', 'family_name') || rawLead.last_name || null;
  normalized.email = getGoogleField('email', 'user_email') || rawLead.email || null;
  normalized.phone = getGoogleField('phone', 'phone_number', 'user_phone') || rawLead.phone || null;
  normalized.campaign = rawLead.campaign_name || rawLead.campaign || null;
  normalized.adName = rawLead.ad_group_name || rawLead.ad_name || null;
  normalized.formId = rawLead.form_id || rawLead.asset_id || null;
  normalized.rawLeadId = rawLead.lead_id || rawLead.gcl_id || rawLead.gclid || null;
  normalized.vehicleInterest = getGoogleField('vehicle', 'vehicle_interest', 'which_vehicle') || rawLead.vehicle_interest || null;
  if (!normalized.firstName) {
    const fullName = getGoogleField('full_name', 'name') || rawLead.full_name || rawLead.name;
    if (fullName) {
      const parts = fullName.trim().split(/\s+/);
      normalized.firstName = parts[0] || null;
      normalized.lastName = parts.slice(1).join(' ') || normalized.lastName;
    }
  }
} else {
  normalized.firstName = rawLead.first_name || rawLead.firstName || null;
  normalized.lastName = rawLead.last_name || rawLead.lastName || null;
  normalized.email = rawLead.email || null;
  normalized.phone = rawLead.phone || rawLead.phone_number || null;
  normalized.campaign = rawLead.campaign || rawLead.campaign_name || null;
  normalized.formId = rawLead.form_id || null;
  normalized.vehicleInterest = rawLead.vehicle_interest || rawLead.vehicle || null;
}

if (!normalized.email && !normalized.phone) {
  throw new Error('Lead missing both email and phone - cannot process. Source: ' + source);
}

return [{ json: normalized }];

const lead = $input.first().json;
const provider = $env.CRM_PROVIDER || 'activix';
let existingLead = null;
let isNew = true;

try {
  if (provider === 'ghl') {
    const ghlApiKey = $env.GHL_API_KEY;
    const ghlBaseUrl = $env.GHL_BASE_URL || 'https://services.leadconnectorhq.com';
    const locationId = $env.GHL_LOCATION_ID;
    if (lead.email) {
      const emailRes = await fetch(`${ghlBaseUrl}/contacts/search/duplicate?locationId=${locationId}&email=${encodeURIComponent(lead.email)}`, {
        method: 'GET',
        headers: { 'Authorization': `Bearer ${ghlApiKey}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' }
      });
      if (emailRes.ok) {
        const data = await emailRes.json();
        if (data.contact) { existingLead = data.contact; isNew = false; }
      }
    }
    if (isNew && lead.phone) {
      const phoneRes = await fetch(`${ghlBaseUrl}/contacts/search/duplicate?locationId=${locationId}&phone=${encodeURIComponent(lead.phone)}`, {
        method: 'GET',
        headers: { 'Authorization': `Bearer ${ghlApiKey}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' }
      });
      if (phoneRes.ok) {
        const data = await phoneRes.json();
        if (data.contact) { existingLead = data.contact; isNew = false; }
      }
    }
  } else {
    const activixToken = $env.ACTIVIX_API_TOKEN;
    const activixBase = $env.ACTIVIX_BASE_URL || 'https://api.activix.ca';
    if (lead.email) {
      const emailRes = await fetch(`${activixBase}/v2/leads/search?query=${encodeURIComponent(lead.email)}`, {
        method: 'GET',
        headers: { 'Authorization': `Bearer ${activixToken}`, 'Content-Type': 'application/json', 'Accept': 'application/json' }
      });
      if (emailRes.ok) {
        const data = await emailRes.json();
        if (data.data && data.data.length > 0) { existingLead = data.data[0]; isNew = false; }
      }
    }
    if (isNew && lead.phone) {
      const phoneRes = await fetch(`${activixBase}/v2/leads/search?query=${encodeURIComponent(lead.phone)}`, {
        method: 'GET',
        headers: { 'Authorization': `Bearer ${activixToken}`, 'Content-Type': 'application/json', 'Accept': 'application/json' }
      });
      if (phoneRes.ok) {
        const data = await phoneRes.json();
        if (data.data && data.data.length > 0) { existingLead = data.data[0]; isNew = false; }
      }
    }
  }
} catch (err) {
  console.log('CRM search failed, treating as new lead:', err.message);
  isNew = true; existingLead = null;
}

return [{ json: { ...lead, _isNew: isNew, _existingLead: existingLead, _provider: provider } }];
